# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import Optional

def check_user_permission(user_id: int, file_id: int, db_path: str) -> bool:
    """Check if user has permission to access the file"""
    try:
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()
        
        cursor.execute("""
            SELECT COUNT(*) 
            FROM user_permissions 
            WHERE user_id = ? AND file_id = ? AND permission_level > 0
        """, (user_id, file_id))
        
        result = cursor.fetchone()
        conn.close()
        
        return result[0] > 0
    except Exception:
        return False

def read_file_with_permission(user_id: int, file_id: int, file_path: str, db_path: str) -> Optional[str]:
    """Check permissions and read file content if allowed"""
    if not check_user_permission(user_id, file_id, db_path):
        return None
    
    try:
        with open(file_path, 'r', encoding='utf-8') as file:
            return file.read()
    except Exception:
        return None